var seed = GetInt(parameters, "seed", context.Seed);
var scale = GetFloat(parameters, "scale", 2.0f);
var colorA = GetColor(parameters, "colorA", System.Windows.Media.Color.FromRgb(255,50,50));
var colorB = GetColor(parameters, "colorB", System.Windows.Media.Color.FromRgb(50,100,255));
var contrast = GetFloat(parameters, "contrast", 1.0f);
var size = context.TileSize;
var result = new PixelBuffer(size, size);
var aR=colorA.R/255f; var aG=colorA.G/255f; var aB=colorA.B/255f;
var bR=colorB.R/255f; var bG=colorB.G/255f; var bB=colorB.B/255f;
result.ParallelForEachPixel((x, y) =>
{
    var u = x / (float)size * scale;
    var v = y / (float)size * scale;
    var period = Math.Max(1, (int)(size * scale));
    var n1 = TileableFractalNoise(u, v, period, 3, 0.5f, 2f, seed);
    var n2 = TileableFractalNoise(u + 5.3f, v + 9.1f, period, 3, 0.5f, 2f, seed + 37);
    var plasma = MathF.Sin((n1 + n2) * MathF.PI * 2f) * 0.5f + 0.5f;
    plasma = Math.Clamp((plasma - 0.5f) * contrast + 0.5f, 0f, 1f);
    var r = Lerp(aR, bR, plasma);
    var g = Lerp(aG, bG, plasma);
    var b = Lerp(aB, bB, plasma);
    result.SetPixel(x, y, r, g, b, 1f);
});
return result;
